-- StockControl.Admin seed (idempotent where noted)
-- Merged: demo users/warehouses/locations + catalog from client workbook:
--   docs/Voorraad 2025 werkdocument finaal.xlsx  (sheet "Inventaris 2025 Beringen")
-- Columns: Leverancier, Artikelnummer, Product, Verpakking, Voorraad, Eh.prijs
-- Unique Sku/ProductCode per sheet row (numeric suffix; same Artikelnummer can repeat for variants).
-- Regenerate:  node tools/excel-read/generate-seed.cjs  (from repo root)
-- Target: SQL Server. Run after EF migrations.

SET NOCOUNT ON;
SET ANSI_NULLS ON;
SET QUOTED_IDENTIFIER ON;
SET ANSI_PADDING ON;
SET ANSI_WARNINGS ON;
SET ARITHABORT ON;
SET CONCAT_NULL_YIELDS_NULL ON;
SET NUMERIC_ROUNDABORT OFF;

BEGIN TRY
    BEGIN TRAN;

    DECLARE @now datetimeoffset(7) = SYSDATETIMEOFFSET();

    -- --- Reference data (small demo, IF NOT EXISTS) ---
    IF NOT EXISTS (SELECT 1 FROM dbo.warehouses WHERE Code = N'WH01')
        VALUES (N'WH01', N'Main', 1, @now, NULL);

    IF NOT EXISTS (SELECT 1 FROM dbo.warehouses WHERE Code = N'WH02')
        VALUES (N'WH02', N'Branch', 1, @now, NULL);

    DECLARE @wh1 int = (SELECT TOP (1) Id FROM dbo.warehouses WHERE Code = N'WH01');
    DECLARE @wh2 int = (SELECT TOP (1) Id FROM dbo.warehouses WHERE Code = N'WH02');

    IF NOT EXISTS (SELECT 1 FROM dbo.locations WHERE WarehouseId = @wh1 AND Code = N'A01-01')
        VALUES (@wh1, N'A01-01', N'Default (import)', 1, @now, NULL);

    IF NOT EXISTS (SELECT 1 FROM dbo.locations WHERE WarehouseId = @wh1 AND Code = N'B01-01')
        VALUES (@wh1, N'B01-01', N'Aisle B', 1, @now, NULL);

    IF NOT EXISTS (SELECT 1 FROM dbo.locations WHERE WarehouseId = @wh2 AND Code = N'C01-01')
        VALUES (@wh2, N'C01-01', N'Front', 1, @now, NULL);

    DECLARE @locA int = (SELECT TOP (1) Id FROM dbo.locations WHERE WarehouseId = @wh1 AND Code = N'A01-01');

    IF NOT EXISTS (SELECT 1 FROM dbo.users WHERE Username = N'marco')
        VALUES (N'marco', N'Marco', 1, @now, NULL);

    IF NOT EXISTS (SELECT 1 FROM dbo.users WHERE Username = N'operador01')
        VALUES (N'operador01', N'Operador 01', 1, @now, NULL);

    IF NOT EXISTS (SELECT 1 FROM dbo.users WHERE Username = N'teste')
        VALUES (N'teste', N'Teste', 0, @now, NULL);

    -- --- Staging: workbook catalog ---
    IF OBJECT_ID('tempdb..#inv') IS NOT NULL DROP TABLE #inv;
    CREATE TABLE #inv (
        SupplierCode  nvarchar(20)  NOT NULL,
        SupplierName  nvarchar(100) NOT NULL,
        ProductCode   nvarchar(40)  NOT NULL,
        ProductName   nvarchar(50)  NOT NULL,
        Sku           nvarchar(40)  NOT NULL,
        DisplayName   nvarchar(50)  NOT NULL,
        Unit          nvarchar(10)  NOT NULL,
        PackagingType int           NOT NULL,
        PackageQty    decimal(18,3) NOT NULL,
        Price         decimal(18,2) NOT NULL,
        StockQty      decimal(18,3) NOT NULL
    );





























    -- Suppliers from import
    SELECT DISTINCT i.SupplierCode, i.SupplierName, 1, @now, NULL
    FROM #inv i
    WHERE NOT EXISTS (SELECT 1 FROM dbo.suppliers s WHERE s.Code = i.SupplierCode);

    -- Products (1:1 code with item Sku in this seed)
    SELECT sup.Id, x.ProductCode, x.ProductName, 1, @now, NULL
    FROM (SELECT DISTINCT SupplierCode, ProductCode, ProductName FROM #inv) x
    INNER JOIN dbo.suppliers sup ON sup.Code = x.SupplierCode
    WHERE NOT EXISTS (SELECT 1 FROM dbo.products p WHERE p.Code = x.ProductCode);

    -- Items
    SELECT pr.Id, v.Sku, v.DisplayName, v.Unit, v.PackagingType, v.PackageQty, v.Price, 1, @now, NULL
    FROM #inv v
    INNER JOIN dbo.products pr ON pr.Code = v.ProductCode
    WHERE NOT EXISTS (SELECT 1 FROM dbo.items it WHERE it.Sku = v.Sku);

    -- Stock on hand (WH01 + default location A01-01)
    SELECT @wh1, @locA, it.Id, v.StockQty, 1, @now, NULL
    FROM #inv v
    INNER JOIN dbo.items it ON it.Sku = v.Sku
    WHERE v.StockQty > 0
      AND NOT EXISTS (
          SELECT 1 FROM dbo.stock_balances sb
          WHERE sb.WarehouseId = @wh1 AND sb.LocationId = @locA AND sb.ItemId = it.Id);

    -- --- Legacy demo catalog (only if SKUs not already present; for Admin smoke tests) ---
    IF NOT EXISTS (SELECT 1 FROM dbo.items WHERE Sku = N'SKU-0001')
    BEGIN
        IF NOT EXISTS (SELECT 1 FROM dbo.suppliers WHERE Code = N'SUP-01')
            VALUES (N'SUP-01', N'Acme Supply (demo)', 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.suppliers WHERE Code = N'SUP-02')
            VALUES (N'SUP-02', N'Global Parts Ltd (demo)', 1, @now, NULL);

        DECLARE @supd1 int = (SELECT TOP (1) Id FROM dbo.suppliers WHERE Code = N'SUP-01');
        DECLARE @supd2 int = (SELECT TOP (1) Id FROM dbo.suppliers WHERE Code = N'SUP-02');

        IF NOT EXISTS (SELECT 1 FROM dbo.products WHERE Code = N'PRD-0001')
            VALUES (@supd1, N'PRD-0001', N'Fasteners (demo)', 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.products WHERE Code = N'PRD-0002')
            VALUES (@supd2, N'PRD-0002', N'Cable ties (demo)', 1, @now, NULL);

        DECLARE @prdd1 int = (SELECT TOP (1) Id FROM dbo.products WHERE Code = N'PRD-0001');
        DECLARE @prdd2 int = (SELECT TOP (1) Id FROM dbo.products WHERE Code = N'PRD-0002');


        DECLARE @dit1 int = (SELECT TOP (1) Id FROM dbo.items WHERE Sku = N'SKU-0001');
        DECLARE @dit2 int = (SELECT TOP (1) Id FROM dbo.items WHERE Sku = N'SKU-0002');
        DECLARE @dit3 int = (SELECT TOP (1) Id FROM dbo.items WHERE Sku = N'SKU-0003');
        DECLARE @dit4 int = (SELECT TOP (1) Id FROM dbo.items WHERE Sku = N'SKU-0004');

        IF NOT EXISTS (SELECT 1 FROM dbo.item_barcodes WHERE Code = N'8712345678901')
        IF NOT EXISTS (SELECT 1 FROM dbo.item_barcodes WHERE Code = N'8712345678902')
        IF NOT EXISTS (SELECT 1 FROM dbo.item_barcodes WHERE Code = N'8712345678903')
        IF NOT EXISTS (SELECT 1 FROM dbo.item_barcodes WHERE Code = N'8712345678904')

        DECLARE @locBdemo int = (SELECT TOP (1) Id FROM dbo.locations WHERE WarehouseId = @wh1 AND Code = N'B01-01');
        DECLARE @locCdemo int = (SELECT TOP (1) Id FROM dbo.locations WHERE WarehouseId = @wh2 AND Code = N'C01-01');

        IF NOT EXISTS (SELECT 1 FROM dbo.minmax_settings WHERE WarehouseId = @wh1 AND ItemId = @dit1 AND LocationId IS NULL)
            VALUES (@wh1, @dit1, NULL, 10, 200, 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.minmax_settings WHERE WarehouseId = @wh1 AND ItemId = @dit2 AND LocationId = @locA)
            VALUES (@wh1, @dit2, @locA, 40, 120, 1, @now, NULL);

        IF NOT EXISTS (SELECT 1 FROM dbo.stock_balances WHERE WarehouseId = @wh1 AND LocationId = @locA AND ItemId = @dit1)
            VALUES (@wh1, @locA, @dit1, 8.000, 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.stock_balances WHERE WarehouseId = @wh1 AND LocationId = @locA AND ItemId = @dit2)
            VALUES (@wh1, @locA, @dit2, 65.000, 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.stock_balances WHERE WarehouseId = @wh1 AND LocationId = @locBdemo AND ItemId = @dit1)
            VALUES (@wh1, @locBdemo, @dit1, 140.000, 1, @now, NULL);
        IF NOT EXISTS (SELECT 1 FROM dbo.stock_balances WHERE WarehouseId = @wh2 AND LocationId = @locCdemo AND ItemId = @dit2)
            VALUES (@wh2, @locCdemo, @dit2, 10.000, 1, @now, NULL);
    END

    DROP TABLE #inv;

    COMMIT;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK;
    THROW;
END CATCH
